const screens = {
  dashboard: {
    uri: "data:text/html;base64,",
    title: "Aura Home Dashboard",
    desc: "— Main ambient control hub",
    icon: "airwave",
    num: "1 / 4"
  },
  biometric: {
    uri: "data:text/html;base64,",
    title: "Biometric Insights",
    desc: "— Health & body data",
    icon: "monitor_heart",
    num: "2 / 4"
  },
  atmosphere: {
    uri: "data:text/html;base64,",
    title: "Atmosphere Customizer",
    desc: "— Light, temperature & scent",
    icon: "nest_thermostat",
    num: "3 / 4"
  },
  schedule: {
    uri: "data:text/html;base64,",
    title: "Predictive Schedule",
    desc: "— AI-driven daily timeline",
    icon: "calendar_clock",
    num: "4 / 4"
  }
};

function switchScreen(btn) {
  const key = btn.dataset.screen;
  const s = screens[key];

  // Update active state
  document.querySelectorAll('.nav-item').forEach(b => b.classList.remove('active'));
  btn.classList.add('active');

  // Update frame
  document.getElementById('screenFrame').src = s.uri;

  // Update top bar
  document.getElementById('screenTitle').textContent = s.title;
  document.getElementById('screenDesc').textContent = s.desc;
  document.getElementById('screenPill').textContent = s.num;
  document.querySelector('#screenBar .material-symbols-outlined').textContent = s.icon;

  // Close sidebar on mobile
  closeSidebar();
}

// Mobile hamburger
const hamburger = document.getElementById('hamburger');
const sidebar = document.getElementById('sidebar');
const overlay = document.getElementById('overlay');

function closeSidebar() {
  sidebar.classList.remove('open');
  overlay.classList.remove('show');
}

hamburger.addEventListener('click', () => {
  const isOpen = sidebar.classList.contains('open');
  if (isOpen) {
    closeSidebar();
  } else {
    sidebar.classList.add('open');
    overlay.classList.add('show');
  }
});

overlay.addEventListener('click', closeSidebar);